import React, { useState } from 'react';

const PipelineHubVisual = () => {
  const [activeView, setActiveView] = useState('overview');
  const [selectedNode, setSelectedNode] = useState(null);
  const [activeState, setActiveState] = useState('editing_hook');
  const [faders, setFaders] = useState({
    game_design: 65,
    fabrication: 40,
    coordination: 80,
    authority: 55,
    energy: 30
  });

  const expertiseScore = Math.round((faders.game_design + faders.fabrication + faders.coordination) / 3);
  const toneScore = Math.round((faders.authority + faders.energy) / 2);
  const leadDomain = Object.entries(faders).slice(0, 3).sort((a, b) => b[1] - a[1])[0][0];

  const states = [
    { id: 'idle', label: 'IDLE', color: '#908388' },
    { id: 'input', label: 'INPUT', color: '#1D719D' },
    { id: 'generating', label: 'GENERATING', color: '#C4841D' },
    { id: 'editing_hook', label: 'EDIT HOOK', color: '#63DAFC' },
    { id: 'editing_setup', label: 'EDIT SETUP', color: '#63DAFC' },
    { id: 'reviewing', label: 'REVIEWING', color: '#D4A039' },
    { id: 'published', label: 'PUBLISHED', color: '#4CAF50' }
  ];

  const contextByState = {
    idle: { needs: ['user_prefs'], ignores: ['everything else'] },
    input: { needs: ['content_ideas', 'voice_profile', 'past_hooks'], ignores: ['archive', 'analytics'] },
    generating: { needs: ['input_text', 'fader_clusters', 'template', 'voice'], ignores: ['history', 'archive'] },
    editing_hook: { needs: ['current_hook', 'voice', 'post_goal'], ignores: ['other_sections', 'analytics', 'archive'] },
    editing_setup: { needs: ['current_setup', 'hook_context', 'voice'], ignores: ['analytics', 'archive'] },
    reviewing: { needs: ['full_post', 'quality_scores', 'checklist'], ignores: ['generation_params', 'ideas'] },
    published: { needs: ['post_url', 'share_options'], ignores: ['everything else'] }
  };

  const apps = [
    { id: 'post_gen', label: 'Post Generator', port: '3003', color: '#63DAFC' },
    { id: 'photo', label: 'Photo Scanner', port: '3004', color: '#D4A039' },
    { id: 'visual', label: 'Visual Asset', port: '3005', color: '#C4841D' },
    { id: 'visual_id', label: 'Visual ID Studio', port: 'TBD', color: '#908388' }
  ];

  const hubServices = [
    { id: 'state', label: 'State Machine', desc: 'Tracks workflow position' },
    { id: 'funnel', label: 'Context Funnel', desc: 'Filters data for AI' },
    { id: 'pool', label: 'Data Pool', desc: 'Centralized storage' },
    { id: 'ai', label: 'AI Interface', desc: 'Claude connection' }
  ];

  const dataLayers = [
    { id: 'memory', label: 'Memory Cache', desc: 'Session state' },
    { id: 'archive', label: 'Archive', desc: 'All posts + metadata' },
    { id: 'analytics', label: 'Analytics', desc: 'Performance data' }
  ];

  return (
    <div style={{
      minHeight: '100vh',
      backgroundColor: '#020008',
      color: '#ECF0F3',
      fontFamily: "'Work Sans', -apple-system, sans-serif",
      padding: '24px'
    }}>
      <div style={{ marginBottom: '24px' }}>
        <h1 style={{
          fontFamily: "'Space Grotesk', sans-serif",
          fontSize: '28px',
          fontWeight: 700,
          color: '#63DAFC',
          margin: 0
        }}>
          Pipeline Hub — Algorithm Architecture
        </h1>
        <p style={{ color: '#908388', margin: '8px 0 0 0' }}>
          Interactive visualization of system components and data flow
        </p>
      </div>

      <div style={{ display: 'flex', gap: '8px', marginBottom: '24px' }}>
        {['overview', 'context-funnel', 'live-demo'].map(view => (
          <button
            key={view}
            onClick={() => setActiveView(view)}
            style={{
              padding: '10px 20px',
              backgroundColor: activeView === view ? '#1D719D' : '#1A1F2E',
              color: activeView === view ? '#ECF0F3' : '#908388',
              border: 'none',
              borderRadius: '8px',
              cursor: 'pointer',
              fontFamily: "'Bebas Neue', sans-serif",
              fontSize: '14px',
              letterSpacing: '1px',
              textTransform: 'uppercase',
              transition: 'all 0.2s ease'
            }}
          >
            {view.replace('-', ' ')}
          </button>
        ))}
      </div>

      {activeView === 'overview' && (
        <div style={{
          backgroundColor: '#1A1F2E',
          borderRadius: '16px',
          padding: '24px',
          position: 'relative'
        }}>
          <h2 style={{
            fontFamily: "'Space Grotesk', sans-serif",
            color: '#D4A039',
            marginTop: 0,
            fontSize: '18px'
          }}>
            System Architecture
          </h2>

          <div style={{
            display: 'flex',
            justifyContent: 'center',
            gap: '16px',
            marginBottom: '24px'
          }}>
            {apps.map(app => (
              <div
                key={app.id}
                onClick={() => setSelectedNode(app)}
                style={{
                  backgroundColor: '#020008',
                  border: `2px solid ${app.color}`,
                  borderRadius: '12px',
                  padding: '16px 20px',
                  textAlign: 'center',
                  cursor: 'pointer',
                  transition: 'all 0.2s ease',
                  transform: selectedNode?.id === app.id ? 'scale(1.05)' : 'scale(1)',
                  boxShadow: selectedNode?.id === app.id ? `0 0 20px ${app.color}40` : 'none'
                }}
              >
                <div style={{ color: app.color, fontWeight: 600, fontSize: '14px' }}>
                  {app.label}
                </div>
                <div style={{ color: '#908388', fontSize: '11px', marginTop: '4px' }}>
                  Port {app.port}
                </div>
              </div>
            ))}
          </div>

          <div style={{
            display: 'flex',
            justifyContent: 'center',
            marginBottom: '8px'
          }}>
            <svg width="400" height="40">
              <path d="M50,0 L50,20 L350,20 L350,0" fill="none" stroke="#63DAFC" strokeWidth="2" strokeDasharray="4,4"/>
              <path d="M200,20 L200,40" fill="none" stroke="#63DAFC" strokeWidth="2"/>
            </svg>
          </div>

          <div style={{
            backgroundColor: '#1D719D',
            borderRadius: '16px',
            padding: '20px',
            maxWidth: '500px',
            margin: '0 auto 24px auto'
          }}>
            <h3 style={{
              textAlign: 'center',
              margin: '0 0 16px 0',
              fontFamily: "'Space Grotesk', sans-serif",
              fontSize: '16px'
            }}>
              PIPELINE HUB
            </h3>
            <div style={{
              display: 'grid',
              gridTemplateColumns: '1fr 1fr',
              gap: '12px'
            }}>
              {hubServices.map(service => (
                <div
                  key={service.id}
                  onClick={() => setSelectedNode(service)}
                  style={{
                    backgroundColor: '#020008',
                    borderRadius: '8px',
                    padding: '12px',
                    cursor: 'pointer',
                    border: selectedNode?.id === service.id ? '2px solid #63DAFC' : '2px solid transparent',
                    transition: 'all 0.2s ease'
                  }}
                >
                  <div style={{ color: '#63DAFC', fontWeight: 600, fontSize: '13px' }}>
                    {service.label}
                  </div>
                  <div style={{ color: '#908388', fontSize: '11px', marginTop: '4px' }}>
                    {service.desc}
                  </div>
                </div>
              ))}
            </div>
          </div>

          <div style={{
            display: 'flex',
            justifyContent: 'center',
            marginBottom: '8px'
          }}>
            <svg width="400" height="40">
              <path d="M100,0 L100,40" fill="none" stroke="#D4A039" strokeWidth="2"/>
              <path d="M200,0 L200,40" fill="none" stroke="#D4A039" strokeWidth="2"/>
              <path d="M300,0 L300,40" fill="none" stroke="#D4A039" strokeWidth="2"/>
            </svg>
          </div>

          <div style={{
            display: 'flex',
            justifyContent: 'center',
            gap: '16px'
          }}>
            {dataLayers.map(layer => (
              <div
                key={layer.id}
                onClick={() => setSelectedNode(layer)}
                style={{
                  backgroundColor: '#020008',
                  border: '2px solid #D4A039',
                  borderRadius: '12px',
                  padding: '16px 24px',
                  textAlign: 'center',
                  cursor: 'pointer',
                  transition: 'all 0.2s ease',
                  transform: selectedNode?.id === layer.id ? 'scale(1.05)' : 'scale(1)'
                }}
              >
                <div style={{ color: '#D4A039', fontWeight: 600, fontSize: '14px' }}>
                  {layer.label}
                </div>
                <div style={{ color: '#908388', fontSize: '11px', marginTop: '4px' }}>
                  {layer.desc}
                </div>
              </div>
            ))}
          </div>

          {selectedNode && (
            <div style={{
              marginTop: '24px',
              backgroundColor: '#020008',
              borderRadius: '12px',
              padding: '16px',
              borderLeft: '4px solid #63DAFC'
            }}>
              <div style={{ color: '#63DAFC', fontWeight: 600, marginBottom: '8px' }}>
                {selectedNode.label}
              </div>
              <div style={{ color: '#908388', fontSize: '14px' }}>
                {selectedNode.desc || `Port: ${selectedNode.port}`}
              </div>
            </div>
          )}
        </div>
      )}

      {activeView === 'context-funnel' && (
        <div style={{
          backgroundColor: '#1A1F2E',
          borderRadius: '16px',
          padding: '24px'
        }}>
          <h2 style={{
            fontFamily: "'Space Grotesk', sans-serif",
            color: '#D4A039',
            marginTop: 0,
            fontSize: '18px'
          }}>
            Context Funnel — What AI Actually Needs
          </h2>

          <p style={{ color: '#908388', marginBottom: '24px' }}>
            Click a state to see what context gets loaded. Not compression—just relevance filtering.
          </p>

          <div style={{
            display: 'flex',
            flexWrap: 'wrap',
            gap: '8px',
            marginBottom: '24px'
          }}>
            {states.map(state => (
              <button
                key={state.id}
                onClick={() => setActiveState(state.id)}
                style={{
                  padding: '8px 16px',
                  backgroundColor: activeState === state.id ? state.color : '#020008',
                  color: activeState === state.id ? '#020008' : state.color,
                  border: `2px solid ${state.color}`,
                  borderRadius: '20px',
                  cursor: 'pointer',
                  fontWeight: 600,
                  fontSize: '12px',
                  transition: 'all 0.2s ease'
                }}
              >
                {state.label}
              </button>
            ))}
          </div>

          <div style={{ display: 'flex', gap: '24px' }}>
            <div style={{ flex: 1 }}>
              <h3 style={{ color: '#FF3B30', fontSize: '14px', marginBottom: '12px' }}>
                ❌ FULL DATA UNIVERSE (Don't Load)
              </h3>
              <div style={{
                backgroundColor: '#020008',
                borderRadius: '12px',
                padding: '16px',
                border: '2px solid #FF3B3040'
              }}>
                {['All chat history', '121 content ideas', 'Full archive', 'Analytics data', 'All fader values', 'Other sections', 'User preferences', 'Generation params'].map(item => (
                  <div
                    key={item}
                    style={{
                      padding: '8px 12px',
                      backgroundColor: contextByState[activeState]?.ignores?.some(i => 
                        item.toLowerCase().includes(i.toLowerCase()) || i === 'everything else'
                      ) ? '#FF3B3020' : '#1A1F2E',
                      borderRadius: '6px',
                      marginBottom: '6px',
                      fontSize: '13px',
                      color: '#908388',
                      textDecoration: contextByState[activeState]?.ignores?.some(i => 
                        item.toLowerCase().includes(i.toLowerCase()) || i === 'everything else'
                      ) ? 'line-through' : 'none'
                    }}
                  >
                    {item}
                  </div>
                ))}
              </div>
            </div>

            <div style={{
              display: 'flex',
              alignItems: 'center',
              fontSize: '32px',
              color: '#63DAFC'
            }}>
              →
            </div>

            <div style={{ flex: 1 }}>
              <h3 style={{ color: '#4CAF50', fontSize: '14px', marginBottom: '12px' }}>
                ✓ AI CONTEXT PACKET (Load This)
              </h3>
              <div style={{
                backgroundColor: '#020008',
                borderRadius: '12px',
                padding: '16px',
                border: '2px solid #4CAF5040'
              }}>
                <div style={{
                  backgroundColor: '#1D719D',
                  borderRadius: '8px',
                  padding: '12px',
                  marginBottom: '12px'
                }}>
                  <div style={{ color: '#63DAFC', fontWeight: 600, fontSize: '12px', marginBottom: '8px' }}>
                    STATE: {activeState.toUpperCase().replace('_', ' ')}
                  </div>
                  <div style={{ color: '#ECF0F3', fontSize: '13px' }}>
                    Needs to know:
                  </div>
                  {contextByState[activeState]?.needs?.map(need => (
                    <div
                      key={need}
                      style={{
                        padding: '6px 10px',
                        backgroundColor: '#4CAF5030',
                        borderRadius: '4px',
                        marginTop: '6px',
                        fontSize: '12px',
                        color: '#4CAF50'
                      }}
                    >
                      • {need.replace('_', ' ')}
                    </div>
                  ))}
                </div>

                <div style={{
                  backgroundColor: '#1A1F2E',
                  borderRadius: '8px',
                  padding: '12px',
                  fontSize: '12px',
                  color: '#908388'
                }}>
                  <strong style={{ color: '#D4A039' }}>Decision Question:</strong>
                  <br />
                  {activeState === 'idle' && '"What does user want to do?"'}
                  {activeState === 'input' && '"What content should we generate?"'}
                  {activeState === 'generating' && '"How to execute this generation?"'}
                  {activeState === 'editing_hook' && '"How to improve this hook?"'}
                  {activeState === 'editing_setup' && '"How to improve this setup?"'}
                  {activeState === 'reviewing' && '"Is this post ready to publish?"'}
                  {activeState === 'published' && '"What next?"'}
                </div>
              </div>
            </div>
          </div>
        </div>
      )}

      {activeView === 'live-demo' && (
        <div style={{
          backgroundColor: '#1A1F2E',
          borderRadius: '16px',
          padding: '24px'
        }}>
          <h2 style={{
            fontFamily: "'Space Grotesk', sans-serif",
            color: '#D4A039',
            marginTop: 0,
            fontSize: '18px'
          }}>
            Live Demo — Variable Clustering
          </h2>

          <p style={{ color: '#908388', marginBottom: '24px' }}>
            Adjust faders to see how they cluster into scores. AI gets the cluster, not individual values.
          </p>

          <div style={{ display: 'flex', gap: '32px' }}>
            <div style={{ flex: 1 }}>
              <h3 style={{ color: '#63DAFC', fontSize: '14px', marginBottom: '16px' }}>
                RAW FADER VALUES (5 variables)
              </h3>
              <div style={{
                backgroundColor: '#020008',
                borderRadius: '12px',
                padding: '20px'
              }}>
                {Object.entries(faders).map(([key, value]) => (
                  <div key={key} style={{ marginBottom: '16px' }}>
                    <div style={{
                      display: 'flex',
                      justifyContent: 'space-between',
                      marginBottom: '6px'
                    }}>
                      <span style={{
                        color: '#ECF0F3',
                        fontSize: '13px',
                        textTransform: 'capitalize'
                      }}>
                        {key.replace('_', ' ')}
                      </span>
                      <span style={{ color: '#63DAFC', fontWeight: 600 }}>
                        {value}
                      </span>
                    </div>
                    <input
                      type="range"
                      min="0"
                      max="100"
                      value={value}
                      onChange={(e) => setFaders({
                        ...faders,
                        [key]: parseInt(e.target.value)
                      })}
                      style={{
                        width: '100%',
                        accentColor: '#63DAFC'
                      }}
                    />
                  </div>
                ))}
              </div>
            </div>

            <div style={{
              display: 'flex',
              flexDirection: 'column',
              alignItems: 'center',
              justifyContent: 'center',
              color: '#D4A039'
            }}>
              <div style={{ fontSize: '12px', marginBottom: '8px' }}>
                PROCESSING
              </div>
              <div style={{ fontSize: '32px' }}>→</div>
              <div style={{ fontSize: '12px', marginTop: '8px' }}>
                LAYER
              </div>
            </div>

            <div style={{ flex: 1 }}>
              <h3 style={{ color: '#4CAF50', fontSize: '14px', marginBottom: '16px' }}>
                CLUSTERED OUTPUT (2 values)
              </h3>
              <div style={{
                backgroundColor: '#020008',
                borderRadius: '12px',
                padding: '20px'
              }}>
                <div style={{
                  backgroundColor: '#1D719D',
                  borderRadius: '8px',
                  padding: '16px',
                  marginBottom: '12px'
                }}>
                  <div style={{ color: '#908388', fontSize: '11px', marginBottom: '4px' }}>
                    EXPERTISE CLUSTER
                  </div>
                  <div style={{ color: '#63DAFC', fontSize: '32px', fontWeight: 700 }}>
                    {expertiseScore}
                  </div>
                  <div style={{ color: '#ECF0F3', fontSize: '12px', marginTop: '4px' }}>
                    Lead: <span style={{ color: '#D4A039' }}>{leadDomain.replace('_', ' ')}</span>
                  </div>
                </div>

                <div style={{
                  backgroundColor: '#C4841D30',
                  borderRadius: '8px',
                  padding: '16px',
                  marginBottom: '12px'
                }}>
                  <div style={{ color: '#908388', fontSize: '11px', marginBottom: '4px' }}>
                    TONE CLUSTER
                  </div>
                  <div style={{ color: '#D4A039', fontSize: '32px', fontWeight: 700 }}>
                    {toneScore}
                  </div>
                  <div style={{ color: '#ECF0F3', fontSize: '12px', marginTop: '4px' }}>
                    Profile: <span style={{ color: '#D4A039' }}>
                      {toneScore < 40 ? 'calm_observer' : toneScore < 70 ? 'balanced_moderate' : 'high_energy'}
                    </span>
                  </div>
                </div>

                <div style={{
                  backgroundColor: '#1A1F2E',
                  borderRadius: '8px',
                  padding: '12px',
                  fontFamily: 'monospace',
                  fontSize: '11px',
                  color: '#908388'
                }}>
                  <div style={{ color: '#4CAF50', marginBottom: '8px' }}>
                    // What AI receives:
                  </div>
                  {`{`}<br />
                  &nbsp;&nbsp;{`"expertise": ${expertiseScore},`}<br />
                  &nbsp;&nbsp;{`"lead": "${leadDomain}",`}<br />
                  &nbsp;&nbsp;{`"tone": ${toneScore},`}<br />
                  &nbsp;&nbsp;{`"profile": "${toneScore < 40 ? 'calm' : toneScore < 70 ? 'balanced' : 'energetic'}"`}<br />
                  {`}`}
                </div>
              </div>
            </div>
          </div>

          <div style={{
            marginTop: '24px',
            backgroundColor: '#020008',
            borderRadius: '12px',
            padding: '16px',
            borderLeft: '4px solid #63DAFC'
          }}>
            <strong style={{ color: '#63DAFC' }}>Key Insight:</strong>
            <span style={{ color: '#ECF0F3', marginLeft: '8px' }}>
              AI doesn't calculate clusters—the processing layer does. AI just receives the result and makes decisions based on it.
            </span>
          </div>
        </div>
      )}
    </div>
  );
};

export default PipelineHubVisual;
```

---

**Three interactive tabs:**

1. **Overview** — Click on apps, hub services, or data layers to see details
2. **Context Funnel** — Click different states to see what context each one needs vs. ignores
3. **Live Demo** — Drag faders and watch clustering happen in real-time

Uses your brand colors from the type specimen. Want me to add more sections or tweak anything?
